// src/components/OdontogramaSimples.js
import React, { useState } from "react";

// Lista dos 32 dentes permanentes (odontograma universal)
const dentes = [
  // Quadrante 1
  { numero: 18, pos: [30, 30] }, { numero: 17, pos: [60, 30] }, { numero: 16, pos: [90, 30] },
  { numero: 15, pos: [120, 30] }, { numero: 14, pos: [150, 30] }, { numero: 13, pos: [180, 30] },
  { numero: 12, pos: [210, 30] }, { numero: 11, pos: [240, 30] },
  // Quadrante 2
  { numero: 21, pos: [270, 30] }, { numero: 22, pos: [300, 30] }, { numero: 23, pos: [330, 30] },
  { numero: 24, pos: [360, 30] }, { numero: 25, pos: [390, 30] }, { numero: 26, pos: [420, 30] },
  { numero: 27, pos: [450, 30] }, { numero: 28, pos: [480, 30] },
  // Quadrante 3
  { numero: 48, pos: [480, 100] }, { numero: 47, pos: [450, 100] }, { numero: 46, pos: [420, 100] },
  { numero: 45, pos: [390, 100] }, { numero: 44, pos: [360, 100] }, { numero: 43, pos: [330, 100] },
  { numero: 42, pos: [300, 100] }, { numero: 41, pos: [270, 100] },
  // Quadrante 4
  { numero: 31, pos: [240, 100] }, { numero: 32, pos: [210, 100] }, { numero: 33, pos: [180, 100] },
  { numero: 34, pos: [150, 100] }, { numero: 35, pos: [120, 100] }, { numero: 36, pos: [90, 100] },
  { numero: 37, pos: [60, 100] }, { numero: 38, pos: [30, 100] },
];

const coresStatus = {
  saudavel: "#a3e635", // verde
  restaurado: "#3b82f6", // azul
  cariado: "#f59e42", // laranja
  ausente: "#f43f5e", // vermelho
};

const listaStatus = ["saudavel", "cariado", "restaurado", "ausente"];

export default function OdontogramaSimples({ value, onChange }) {
  // Estado interno: status de cada dente
  const [status, setStatus] = useState(() =>
    dentes.reduce((obj, d) => ({ ...obj, [d.numero]: "saudavel" }), {})
  );

  // Atualiza status do dente clicado (gira os status)
  function handleClick(numero) {
    const atual = status[numero];
    const proxIndex = (listaStatus.indexOf(atual) + 1) % listaStatus.length;
    const novoStatus = listaStatus[proxIndex];
    const atualizado = { ...status, [numero]: novoStatus };
    setStatus(atualizado);
    if (onChange) onChange(atualizado);
  }

  return (
    <div>
      <svg width={520} height={170} viewBox="0 0 520 150">
        {/* Dentes superiores */}
        {dentes.slice(0, 16).map((d, i) => (
          <g key={d.numero} onClick={() => handleClick(d.numero)} style={{ cursor: "pointer" }}>
            <circle
              cx={d.pos[0]}
              cy={d.pos[1]}
              r={22}
              fill={coresStatus[status[d.numero]]}
              stroke="#333"
              strokeWidth={2}
            />
            <text
              x={d.pos[0]}
              y={d.pos[1] + 5}
              textAnchor="middle"
              fontSize={16}
              fill="#1A1C2C"
              fontWeight={600}
            >
              {d.numero}
            </text>
          </g>
        ))}
        {/* Dentes inferiores */}
        {dentes.slice(16, 32).map((d, i) => (
          <g key={d.numero} onClick={() => handleClick(d.numero)} style={{ cursor: "pointer" }}>
            <circle
              cx={d.pos[0]}
              cy={d.pos[1]}
              r={22}
              fill={coresStatus[status[d.numero]]}
              stroke="#333"
              strokeWidth={2}
            />
            <text
              x={d.pos[0]}
              y={d.pos[1] + 5}
              textAnchor="middle"
              fontSize={16}
              fill="#1A1C2C"
              fontWeight={600}
            >
              {d.numero}
            </text>
          </g>
        ))}
      </svg>
      <div className="flex gap-4 mt-4">
        {listaStatus.map(st => (
          <span key={st} className="flex items-center gap-2">
            <span style={{
              display: "inline-block",
              width: 18,
              height: 18,
              borderRadius: "50%",
              background: coresStatus[st],
              border: "1.5px solid #333"
            }}></span>
            <span className="capitalize">{st}</span>
          </span>
        ))}
      </div>
    </div>
  );
}
